('How FinFlows Automated 90% of Their Back-Office Operations', 'finflows-back-office-automation', 'Case Study', 'AI-powered workflow automation that eliminated manual processing and cut operational costs by 60%.', 'FinFlows, a fast-growing fintech platform, partnered with Digi Pexel to automate their loan processing, KYC verification, and monthly reporting pipelines.', 'FinFlows Inc.', 'Fintech', 'https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=800&q=80', 'Start Your Project', '/contact-us', '[{\"label\":\"Ops Cost Reduction\",\"value\":\"60%\"},{\"label\":\"Processes Automated\",\"value\":\"40+\"},{\"label\":\"Hours Saved / Week\",\"value\":\"320h\"},{\"label\":\"ROI in 90 Days\",\"value\":\"4.2x\"}]', '[{\"id\":\"c1\",\"type\":\"challenge\",\"title\":\"The Problem: Manual Overload\",\"content\":\"The FinFlows ops team was spending 320 hours per week on manual loan processing, document verification, and compliance reporting. Error rates were high and the team could not scale without proportional headcount growth.\",\"points\":[\"48-hour average KYC verification time\",\"12% error rate on manual data entry\",\"Compliance reporting took 3 full-time employees\"]},{\"id\":\"c2\",\"type\":\"solution\",\"title\":\"The Approach: Autonomous Agent Stack\",\"content\":\"Digi Pexel designed a multi-agent automation system covering identity verification, document parsing, decision routing, and report generation — all orchestrated through a centralised workflow engine.\",\"points\":[\"Custom AI agent for document parsing and entity extraction\",\"Automated KYC decision routing with human escalation path\",\"Real-time compliance report generation via API integration\"]},{\"id\":\"c3\",\"type\":\"metrics\",\"title\":\"Results After 90 Days\",\"content\":\"Measured against pre-deployment baseline.\",\"metrics\":[{\"value\":\"60%\",\"label\":\"Ops cost reduction\",\"desc\":\"Year-one savings\"},{\"value\":\"4 hrs\",\"label\":\"KYC verification\",\"desc\":\"Down from 48 hours\"},{\"value\":\"99.1%\",\"label\":\"Data accuracy\",\"desc\":\"Up from 88%\"},{\"value\":\"4.2x\",\"label\":\"ROI\",\"desc\":\"Within 90 days\"}]}]', 'published', 0, '2025-03-14')");

    $pdo->exec("INSERT IGNORE INTO case_studies (title, slug, eyebrow, subtitle, description, client_name, industry, image_url, hero_cta_label, hero_cta_url, hero_stats, sections, status, position, published_date) VALUES
('How GrowthLoop Scaled LinkedIn Outreach 10x Without Hiring', 'growthloop-linkedin-scale', 'Case Study', 'AI-driven social selling automation that tripled qualified pipeline in 60 days.', 'GrowthLoop, a B2B SaaS company, needed to scale their outbound pipeline without expanding their SDR team. Digi Pexel built an autonomous LinkedIn prospecting and nurture system.', 'GrowthLoop', 'B2B SaaS', 'https://images.unsplash.com/photo-1460925895917-afdab827c52f?w=800&q=80', 'Start Your Project', '/contact-us', '[{\"label\":\"Pipeline Growth\",\"value\":\"3x\"},{\"label\":\"SDR Hours Saved\",\"value\":\"120/wk\"},{\"label\":\"Response Rate\",\"value\":\"34%\"},{\"label\":\"Time to Deploy\",\"value\":\"3 wks\"}]', '[{\"id\":\"c1\",\"type\":\"challenge\",\"title\":\"The Problem: Outbound at a Ceiling\",\"content\":\"GrowthLoop had a skilled but overloaded SDR team spending 70% of their time on manual prospecting, personalisation, and follow-up. Conversion rates were flat despite headcount growth.\",\"points\":[\"SDRs spending 5+ hours daily on manual list building\",\"Inconsistent follow-up cadence losing warm leads\",\"Personalisation at scale impossible without automation\"]},{\"id\":\"c2\",\"type\":\"solution\",\"title\":\"The Approach: AI Social Selling Engine\",\"content\":\"We built an autonomous LinkedIn prospecting workflow combining AI-powered personalisation, smart sequencing, and intent-based prioritisation — all without violating platform terms.\",\"points\":[\"AI personalisation engine generating custom openers from profile data\",\"Intent-based prioritisation surfacing high-signal accounts daily\",\"Automated multi-touch sequences with human handoff triggers\"]},{\"id\":\"c3\",\"type\":\"metrics\",\"title\":\"Results After 60 Days\",\"content\":\"Measured against the 60-day pre-deployment baseline.\",\"metrics\":[{\"value\":\"3x\",\"label\":\"Qualified pipeline\",\"desc\":\"vs. prior period\"},{\"value\":\"34%\",\"label\":\"Response rate\",\"desc\":\"From 11% baseline\"},{\"value\":\"120 hrs\",\"label\":\"SDR time saved\",\"desc\":\"Per week across team\"},{\"value\":\"3 wks\",\"label\":\"Deployment time\",\"desc\":\"From kickoff to live\"}]}]', 'published', 1, '2025-04-10')");

    $pdo->exec("INSERT IGNORE INTO case_studies (title, slug, eyebrow, subtitle, description, client_name, industry, image_url, hero_cta_label, hero_cta_url, hero_stats, sections, status, position, published_date) VALUES
('How MediTrack Cut Patient Onboarding From 9 Days to 6 Hours', 'meditrack-patient-onboarding-automation', 'Case Study', 'AI-powered document intake and verification that eliminated manual processing across 4 clinic locations.', 'MediTrack, a multi-location healthcare SaaS provider, engaged Digi Pexel to automate their patient onboarding pipeline — reducing delays, eliminating manual data entry, and achieving near-instant eligibility checks.', 'MediTrack Health', 'Healthcare SaaS', 'https://images.unsplash.com/photo-1576091160399-112ba8d25d1d?w=800&q=80', 'Start Your Project', '/contact-us', '[{\"label\":\"Onboarding Time\",\"value\":\"-93%\"},{\"label\":\"Manual Steps Eliminated\",\"value\":\"28\"},{\"label\":\"Staff Hours Saved/Wk\",\"value\":\"210h\"},{\"label\":\"Error Rate\",\"value\":\"0.3%\"}]', '[{\"id\":\"c1\",\"type\":\"challenge\",\"title\":\"The Problem: 9-Day Onboarding Backlog\",\"content\":\"MediTrack staff were spending 9 days on average processing each new patient: manually entering referral data from faxes and PDFs, checking insurance eligibility across 3 separate portals, and coordinating appointment scheduling via email threads.\",\"points\":[\"9-day average patient onboarding cycle\",\"4.2% data entry error rate causing claim rejections\",\"210 staff hours per week lost to manual intake tasks\"]},{\"id\":\"c2\",\"type\":\"solution\",\"title\":\"The Approach: Document AI + Eligibility Automation\",\"content\":\"Digi Pexel deployed a multi-stage AI pipeline that reads intake documents, extracts structured patient data, verifies insurance eligibility via API, and routes completed records directly into the EHR system — with a human checkpoint only for flagged edge cases.\",\"points\":[\"Document parsing agent extracting 40+ data fields from PDFs and images\",\"Real-time insurance eligibility verification via payer API integrations\",\"Automated EHR record creation with conflict-detection rules\",\"Human review queue for less than 3% of cases that trigger exception flags\"]},{\"id\":\"c3\",\"type\":\"metrics\",\"title\":\"Results After 60 Days Live\",\"content\":\"Measured against the 60-day pre-deployment baseline across all 4 clinic locations.\",\"metrics\":[{\"value\":\"6 hrs\",\"label\":\"Onboarding time\",\"desc\":\"Down from 9 days\"},{\"value\":\"0.3%\",\"label\":\"Data error rate\",\"desc\":\"Down from 4.2%\"},{\"value\":\"210 hrs\",\"label\":\"Staff time reclaimed\",\"desc\":\"Per week across locations\"},{\"value\":\"$340k\",\"label\":\"Annual cost saving\",\"desc\":\"Projected year-one\"}]}]', 'published', 2, '2025-04-28')");

    $pdo->exec("INSERT IGNORE INTO case_studies (title, slug, eyebrow, subtitle, description, client_name, industry, image_url, hero_cta_label, hero_cta_url, hero_stats, sections, status, position, published_date) VALUES
('How NexaRetail Automated Inventory Reporting and Saved 480 Ops Hours Monthly', 'nexaretail-inventory-reporting-automation', 'Case Study', 'Replacing weekly manual inventory reconciliation with a fully autonomous AI reporting pipeline.', 'NexaRetail, a fast-growing D2C brand operating across 3 fulfilment centres, partnered with Digi Pexel to automate their inventory reconciliation, stock alert, and supplier reorder workflows.', 'NexaRetail', 'E-Commerce / Retail', 'https://images.unsplash.com/photo-1586528116311-ad8dd3c8310d?w=800&q=80', 'Start Your Project', '/contact-us', '[{\"label\":\"Ops Hours Saved/Mo\",\"value\":\"480h\"},{\"label\":\"Stockout Incidents\",\"value\":\"-78%\"},{\"label\":\"Report Accuracy\",\"value\":\"99.7%\"},{\"label\":\"Deployment Time\",\"value\":\"4 wks\"}]', '[{\"id\":\"c1\",\"type\":\"challenge\",\"title\":\"The Problem: 120-Hour Monthly Reconciliation Drain\",\"content\":\"NexaRetail operations managers were spending 120 hours every month manually reconciling inventory across three warehouse systems, two 3PL providers, and a Shopify storefront. Discrepancies were caught too late, causing frequent stockouts and oversells.\",\"points\":[\"120 hours/month on manual inventory reconciliation\",\"Average 3-day lag between stockout and reorder trigger\",\"18% of weekly reports contained at least one material error\"]},{\"id\":\"c2\",\"type\":\"solution\",\"title\":\"The Approach: Unified Inventory Intelligence Layer\",\"content\":\"Digi Pexel built an automation layer that pulls live inventory data from all warehouse and commerce systems, reconciles discrepancies using rule-based logic, generates daily exception reports, and triggers supplier reorder emails autonomously when par levels are breached.\",\"points\":[\"Unified API sync across Shopify, WMS, and 3PL portals every 4 hours\",\"AI reconciliation engine flagging discrepancies within 15 minutes of detection\",\"Automated supplier reorder emails with PO draft generation\",\"Daily and weekly summary dashboards emailed to leadership at 7am\"]},{\"id\":\"c3\",\"type\":\"metrics\",\"title\":\"Results After 30 Days Live\",\"content\":\"Measured against the 30-day pre-deployment baseline.\",\"metrics\":[{\"value\":\"480 hrs\",\"label\":\"Ops time saved\",\"desc\":\"Per month total\"},{\"value\":\"-78%\",\"label\":\"Stockout incidents\",\"desc\":\"vs. prior 30 days\"},{\"value\":\"99.7%\",\"label\":\"Report accuracy\",\"desc\":\"Up from 82%\"},{\"value\":\"4 wks\",\"label\":\"Time to deploy\",\"desc\":\"Kickoff to full automation\"}]}]', 'published', 3, '2025-05-09')");

